import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';

const sessions = new Map<string, SessionData>();

interface SessionData {
  userId: string;
  email: string;
  createdAt: number;
  expiresAt: number;
}

export function createSession(userId: string, email: string): string {
  const sessionId = crypto.randomUUID();
  sessions.set(sessionId, {
    userId, email,
    createdAt: Date.now(),
    expiresAt: Date.now() + 24 * 60 * 60 * 1000
  });
  return sessionId;
}

export function validateSession(req: Request, res: Response, next: NextFunction) {
  const sessionId = req.cookies?.sessionId;
  if (!sessionId || !sessions.has(sessionId)) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const session = sessions.get(sessionId)!;
  if (session.expiresAt < Date.now()) {
    sessions.delete(sessionId);
    return res.status(401).json({ error: 'Session expired' });
  }
  req.user = { userId: session.userId, email: session.email };
  next();
}

import { validateSession } from './session';
import { Router } from 'express';

const authRouter = Router();
authRouter.use(validateSession);

export default authRouter;

