import { Router, Request, Response } from 'express';
import { createSession } from '../auth/session';
import { findUserByEmail, verifyPassword } from '../services/user';

const loginRouter = Router();

loginRouter.post('/login', async (req: Request, res: Response) => {
  const { email, password } = req.body;
  const user = await findUserByEmail(email);
  if (!user || !await verifyPassword(password, user.passwordHash)) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }
  const sessionId = createSession(user.id, user.email);
  res.cookie('sessionId', sessionId, { httpOnly: true, secure: true });
  res.json({ message: 'Login successful' });
});

export default loginRouter;

import { Router, Request, Response } from 'express';
import { findUserById, updateUser, deleteUser, getUserPreferences, updatePreferences, getUserActivity, getLoginHistory, getSecurityLog, getNotificationSettings, updateNotificationSettings, getUserSubscription, cancelSubscription, getPaymentHistory, getBillingInfo, updateBillingInfo, getUserTeams, getTeamMembers, inviteTeamMember, removeTeamMember, getTeamPermissions, updateTeamPermissions, getAuditLog, exportUserData, requestAccountDeletion, getApiKeys, createApiKey, revokeApiKey, rotateApiKey, getWebhooks, createWebhook, deleteWebhook, testWebhook, getIntegrations, enableIntegration, disableIntegration, getIntegrationConfig, updateIntegrationConfig, getSSOConfig, updateSSOConfig, getMFAStatus, enableMFA, disableMFA, verifyMFAToken, getRecoveryCodes, regenerateRecoveryCodes, getSessionHistory, revokeSession, revokeAllSessions, getDevices, removeDevice, getTrustedDevices, addTrustedDevice, removeTrustedDevice, getSecurityQuestions, setSecurityQuestions, verifySecurityAnswer, getPasswordPolicy, updatePassword, requestPasswordReset, confirmPasswordReset, getEmailVerificationStatus, sendVerificationEmail, verifyEmail, getPhoneVerificationStatus, sendPhoneVerification, verifyPhone, getIdentityProviders, linkIdentityProvider, unlinkIdentityProvider, getLinkedAccounts, mergeAccounts, splitAccount, getUserQuota, getUsageStats, getStorageUsage, requestQuotaIncrease, getUserMetadata, updateUserMetadata, getUserTags, addUserTag, removeUserTag, searchUsers, bulkUpdateUsers, exportUsers, importUsers, getUserSegments, addUserToSegment, removeUserFromSegment, getSegmentRules, createSegment, deleteSegment, getUserEvents, trackEvent, getEventTypes, createEventType, deleteEventType, getUserJourney, getJourneySteps, createJourneyStep, completeJourneyStep, skipJourneyStep, getOnboardingStatus, updateOnboardingStatus, resetOnboarding } from '../services/user';

const profileRouter = Router();

// GET /me - Get current user profile
profileRouter.get('/me', async (req: Request, res: Response) => {
  try {
    const user = await findUserById(req.user.userId);
    if (!user) return res.status(404).json({ error: 'User not found' });
    res.json({
      id: user.id,
      email: user.email,
      name: user.name,
      avatar: user.avatar,
      bio: user.bio,
      location: user.location,
      website: user.website,
      timezone: user.timezone,
      locale: user.locale,
      createdAt: user.createdAt,
      updatedAt: user.updatedAt,
      lastLoginAt: user.lastLoginAt,
      emailVerified: user.emailVerified,
      phoneVerified: user.phoneVerified,
      mfaEnabled: user.mfaEnabled,
      subscription: user.subscription,
      role: user.role,
      permissions: user.permissions,
    });
  } catch (error) {
    console.error('Error fetching user profile:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// PUT /me - Update current user profile
profileRouter.put('/me', async (req: Request, res: Response) => {
  try {
    const allowedFields = ['name', 'bio', 'location', 'website', 'timezone', 'locale', 'avatar'];
    const updates: Record<string, unknown> = {};
    for (const field of allowedFields) {
      if (req.body[field] !== undefined) updates[field] = req.body[field];
    }
    if (Object.keys(updates).length === 0) {
      return res.status(400).json({ error: 'No valid fields to update' });
    }
    const updated = await updateUser(req.user.userId, updates);
    res.json(updated);
  } catch (error) {
    console.error('Error updating user profile:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// DELETE /me - Request account deletion
profileRouter.delete('/me', async (req: Request, res: Response) => {
  try {
    await requestAccountDeletion(req.user.userId);
    res.json({ message: 'Account deletion requested. You will receive a confirmation email.' });
  } catch (error) {
    console.error('Error requesting account deletion:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/preferences - Get user preferences
profileRouter.get('/me/preferences', async (req: Request, res: Response) => {
  try {
    const prefs = await getUserPreferences(req.user.userId);
    res.json(prefs);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// PUT /me/preferences - Update user preferences
profileRouter.put('/me/preferences', async (req: Request, res: Response) => {
  try {
    const updated = await updatePreferences(req.user.userId, req.body);
    res.json(updated);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/activity - Get user activity log
profileRouter.get('/me/activity', async (req: Request, res: Response) => {
  try {
    const page = parseInt(req.query.page as string) || 1;
    const limit = parseInt(req.query.limit as string) || 50;
    const activity = await getUserActivity(req.user.userId, { page, limit });
    res.json(activity);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/security - Get security log
profileRouter.get('/me/security', async (req: Request, res: Response) => {
  try {
    const log = await getSecurityLog(req.user.userId);
    res.json(log);
  } catch (error) {
