});

// GET /me/notifications - Get notification settings
profileRouter.get('/me/notifications', async (req: Request, res: Response) => {
  try {
    const settings = await getNotificationSettings(req.user.userId);
    res.json(settings);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// PUT /me/notifications - Update notification settings
profileRouter.put('/me/notifications', async (req: Request, res: Response) => {
  try {
    const updated = await updateNotificationSettings(req.user.userId, req.body);
    res.json(updated);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/subscription - Get subscription info
profileRouter.get('/me/subscription', async (req: Request, res: Response) => {
  try {
    const sub = await getUserSubscription(req.user.userId);
    res.json(sub);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/billing - Get billing info
profileRouter.get('/me/billing', async (req: Request, res: Response) => {
  try {
    const billing = await getBillingInfo(req.user.userId);
    res.json(billing);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/teams - Get user teams
profileRouter.get('/me/teams', async (req: Request, res: Response) => {
  try {
    const teams = await getUserTeams(req.user.userId);
    res.json(teams);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/api-keys - Get API keys
profileRouter.get('/me/api-keys', async (req: Request, res: Response) => {
  try {
    const keys = await getApiKeys(req.user.userId);
    res.json(keys);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /me/api-keys - Create API key
profileRouter.post('/me/api-keys', async (req: Request, res: Response) => {
  try {
    const key = await createApiKey(req.user.userId, req.body);
    res.status(201).json(key);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /me/mfa - Get MFA status
profileRouter.get('/me/mfa', async (req: Request, res: Response) => {
  try {
    const status = await getMFAStatus(req.user.userId);
    res.json(status);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /me/mfa/enable - Enable MFA
profileRouter.post('/me/mfa/enable', async (req: Request, res: Response) => {
  try {
    const result = await enableMFA(req.user.userId);
    res.json(result);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

// POST /me/password - Update password
profileRouter.post('/me/password', async (req: Request, res: Response) => {
  try {
    const { currentPassword, newPassword } = req.body;
    await updatePassword(req.user.userId, currentPassword, newPassword);
    res.json({ message: 'Password updated successfully' });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

