import { Router, Request, Response } from 'express';
import { createUser, findUserByEmail } from '../services/user';
import { createSession } from '../auth/session';

const registerRouter = Router();

registerRouter.post('/register', async (req: Request, res: Response) => {
  const { email, password, name } = req.body;
  const existing = await findUserByEmail(email);
  if (existing) return res.status(409).json({ error: 'Email already registered' });
  const user = await createUser({ email, password, name });
  const sessionId = createSession(user.id, user.email);
  res.cookie('sessionId', sessionId, { httpOnly: true, secure: true });
  res.status(201).json({ message: 'Registration successful' });
});

export default registerRouter;

// POST /register/verify - Verify email after registration
registerRouter.post('/register/verify', async (req: Request, res: Response) => {
  const { token } = req.body;
  try {
    const decoded = jwt.verify(token, process.env.EMAIL_VERIFY_SECRET!);
    await verifyUserEmail((decoded as any).userId);
    res.json({ message: 'Email verified successfully' });
  } catch {
    res.status(400).json({ error: 'Invalid or expired verification token' });
  }
});

// POST /register/resend-verification - Resend verification email
registerRouter.post('/register/resend-verification', async (req: Request, res: Response) => {
  const { email } = req.body;
  const user = await findUserByEmail(email);
  if (!user) return res.status(404).json({ error: 'User not found' });
  if (user.emailVerified) return res.status(400).json({ error: 'Email already verified' });
  const verifyToken = jwt.sign({ userId: user.id }, process.env.EMAIL_VERIFY_SECRET!, { expiresIn: '24h' });
  await sendVerificationEmail(user.email, verifyToken);
  res.json({ message: 'Verification email sent' });
});

// POST /register/social - Social login/registration
registerRouter.post('/register/social', async (req: Request, res: Response) => {
  const { provider, accessToken, profile } = req.body;
  try {
    let user = await findUserByProvider(provider, profile.id);
    if (!user) {
      user = await createUser({
        email: profile.email,
        name: profile.displayName,
        avatar: profile.photos?.[0]?.value,
        providers: [{ name: provider, id: profile.id }],
      });
    }
    const sessionId = createSession(user.id, user.email);
    res.cookie('sessionId', sessionId, { httpOnly: true, secure: true });
    res.json({ message: 'Social login successful', user: { id: user.id, name: user.name } });
  } catch (error) {
    res.status(500).json({ error: 'Social login failed' });
  }
});

// POST /register/check-email - Check if email is available
registerRouter.post('/register/check-email', async (req: Request, res: Response) => {
  const { email } = req.body;
  const existing = await findUserByEmail(email);
  res.json({ available: !existing });
});

// POST /register/check-username - Check if username is available
registerRouter.post('/register/check-username', async (req: Request, res: Response) => {
  const { username } = req.body;
  const existing = await findUserByUsername(username);
  res.json({ available: !existing });
});

// GET /register/providers - Get available social login providers
registerRouter.get('/register/providers', (_req: Request, res: Response) => {
  res.json({
    providers: [
      { name: 'google', enabled: !!process.env.GOOGLE_CLIENT_ID },
      { name: 'github', enabled: !!process.env.GITHUB_CLIENT_ID },
      { name: 'microsoft', enabled: !!process.env.MICROSOFT_CLIENT_ID },
    ]
  });
});

// POST /register/invite - Register via invite link
registerRouter.post('/register/invite', async (req: Request, res: Response) => {
  const { inviteToken, email, password, name } = req.body;
  try {
    const invite = await validateInvite(inviteToken);
    if (!invite) return res.status(400).json({ error: 'Invalid or expired invite' });
    const user = await createUser({ email, password, name, teamId: invite.teamId, role: invite.role });
    await consumeInvite(inviteToken);
    const sessionId = createSession(user.id, user.email);
    res.cookie('sessionId', sessionId, { httpOnly: true, secure: true });
    res.status(201).json({ message: 'Registration successful via invite' });
  } catch (error) {
    res.status(500).json({ error: 'Registration failed' });
  }
});

export default registerRouter;

// Validation middleware for registration
function validateRegistrationInput(req: Request, res: Response, next: NextFunction) {
  const { email, password, name } = req.body;
  const errors: string[] = [];
  if (!email || !email.match(/^[^@]+@[^@]+\.[^@]+$/)) errors.push('Invalid email address');
  if (!password || password.length < 8) errors.push('Password must be at least 8 characters');
  if (!password.match(/[A-Z]/)) errors.push('Password must contain an uppercase letter');
  if (!password.match(/[0-9]/)) errors.push('Password must contain a number');
  if (!password.match(/[^A-Za-z0-9]/)) errors.push('Password must contain a special character');
  if (!name || name.length < 2) errors.push('Name must be at least 2 characters');
  if (name && name.length > 100) errors.push('Name must be less than 100 characters');
  if (errors.length > 0) return res.status(400).json({ errors });
  next();
}

